import java.io.File;
import java.io.IOException;
import java.nio.file.Files;
import java.nio.file.Paths;

public class SecurePathTraversal {

    public static void main(String[] args) {
        String userInput = "/etc/passwd"; // Example user input
        String basePath = "/path/to/files/";

        // Sanitize user input to prevent path traversal
        String sanitizedInput = userInput.replaceAll("[^a-zA-Z0-9.-]", "");

        String filePath = Paths.get(basePath, sanitizedInput).normalize().toString();

        if (!filePath.startsWith(basePath)) {
            System.out.println("Invalid file path.");
            return;
        }

        File file = new File(filePath);

        if (file.exists()) {
            try {
                byte[] fileData = Files.readAllBytes(file.toPath());
                System.out.println(new String(fileData));
            } catch (IOException e) {
                e.printStackTrace();
            }
        } else {
            System.out.println("File not found.");
        }
    }
}
